WHERE a.deleted_at IS NULL
  AND DATE(a.receipt_date) >= #{startDate}
  AND DATE(a.receipt_date) <= #{endDate}
  AND a.branch_id = #{branchId}
  AND a.status_as = #{statusAs}
  AND a.type_as   = #{typeAs}
  AND a.device_id = #{deviceId}
ORDER BY a.receipt_date DESC

mapper.update:
UPDATE device_as
status_as = #{statusAs}, type_as = #{typeAs}, receipt_date = #{receiptDate}, receipt_details = #{receiptDetails}, checker_name = #{checkerName}, collection_date = #{collectionDate}, manager_name = #{managerName}, repair_details = #{repairDetails}, completion_date = #{completionDate}, redispatch_date = #{redispatchDate},
WHERE as_id = #{asId}
